      "alternatives_rejected": ["Skip __init__ as trivially self-documenting", "Only add docstrings where none exist without enhancing existing ones"],
      "reversibility": "easy"
    },
    {
      "id": "d3",
      "decision": "Do not add usage examples in docstrings. Tests already serve as living documentation and the API is small.",
