      "alternatives_rejected": ["Add doctest-style examples to check method"],
      "reversibility": "easy"
    },
    {
      "id": "d4",
      "decision": "Do not add docstrings to InvalidationResult fields. It is a frozen dataclass with self-documenting field names and already has a class docstring.",
